import streamlit as st

from src.screen.home_screen import Home_screen
from src.screen.Student_screen import Student_screen
from src.screen.Teachers_screen import Teacher_screen
from src.components.dialog_auto_enroll import dialog_auto_enroll

def main():
    st.set_page_config(
        page_title = 'SnapClass - Making Attendance faster using AI',
        page_icon = "data:image/png;base64,"
    )
    if 'login_type' not in st.session_state:
        st.session_state['login_type'] = None

    # FIX 1: check for QR join-code BEFORE rendering screens
    join_code = st.query_params.get('join-code')  # FIX 2: was 'join_code', must match URL param
    if join_code:
        # FIX 3: 'Student' not 'student' — must match session_state values
        if st.session_state['login_type'] != 'Student':
            st.session_state['login_type'] = 'Student'
            st.rerun()
        # FIX 4: was st.session (missing _state), also check login correctly
        if st.session_state.get('is_logged_in') and st.session_state.get('user_role') == 'student':
            dialog_auto_enroll(join_code)
            return  # FIX 5: return after dialog so screen doesn't also render

    match st.session_state['login_type']:
        case 'Teacher':
            Teacher_screen()
        case 'Student':
            Student_screen()
        case None:
            Home_screen()

main()